const parsed = $('解析 LINE 輸入').first().json;
const resp = $input.first().json;

if (resp.error) {
  return [{ json: { ok: false, replyToken: parsed.replyToken, reason: `Gemini 錯誤：${resp.error.message || JSON.stringify(resp.error)}` } }];
}
const aiText = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
if (!aiText) {
  return [{ json: { ok: false, replyToken: parsed.replyToken, reason: 'Gemini 沒回內容（可能 quota 用完或圖片無法辨識）' } }];
}
let ai;
try {
  const clean = aiText.trim().replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
  ai = JSON.parse(clean);
} catch (e) {
  return [{ json: { ok: false, replyToken: parsed.replyToken, reason: `AI 回傳非 JSON：${aiText.slice(0,120)}` } }];
}

const name = String(ai['客戶姓名'] || '').trim();
if (!name) return [{ json: { ok: false, replyToken: parsed.replyToken, reason: '找不到客戶姓名' } }];

const allowedSource = ['591','來電','介紹','路過/踩線','社群','其他'];
const allowedStatus = ['新名單','已聯絡','可帶看','斡旋中','已成交','暫緩/無效','委託中屋主'];
const allowedTags   = ['買方','賣方','租方','出租','急','預算已確認'];

let source = String(ai['來源'] || '其他').trim();
if (!allowedSource.includes(source)) source = '其他';
let status = String(ai['狀態'] || '新名單').trim();
if (!allowedStatus.includes(status)) status = '新名單';
let tags = Array.isArray(ai['標籤']) ? ai['標籤'] : [];
tags = tags.map(t => String(t).trim()).filter(t => allowedTags.includes(t));

const phone   = String(ai['電話'] || '').trim();
const company = String(ai['公司'] || '').trim();
const lineId  = String(ai['LINE'] || '').trim();
const address = String(ai['地址'] || '').trim();
const extra   = String(ai['備註'] || '').trim();
const followup= String(ai['下次追蹤日'] || '').trim();

// 地址塞進備註
const noteParts = [];
if (extra)   noteParts.push(extra);
if (address) noteParts.push(`地址：${address}`);
const note = noteParts.join('\n');

// 組 Notion properties
const properties = {
  '客戶姓名': { title: [{ text: { content: name } }] },
  '來源': { select: { name: source } },
  '狀態': { select: { name: status } }
};
if (phone)   properties['電話'] = { phone_number: phone };
if (company) properties['公司'] = { rich_text: [{ text: { content: company } }] };
if (lineId)  properties['LINE / 通訊軟體'] = { rich_text: [{ text: { content: lineId } }] };
if (note)    properties['備註'] = { rich_text: [{ text: { content: note } }] };
if (tags.length) properties['標籤'] = { multi_select: tags.map(name => ({ name })) };
if (/^\d{4}-\d{2}-\d{2}$/.test(followup)) properties['下次追蹤日'] = { date: { start: followup } };

const body = { parent: { database_id: '3eb9902989534654976e2f677b6957b3' }, properties };
return [{ json: { ok: true, replyToken: parsed.replyToken, name, summary: { phone, company, lineId, source, status, tags, followup }, notionBody: body } }];

const data = $('驗證 + 組 Notion body').first().json;
const resp = $input.first().json;

if (resp.object === 'error' || !resp.id) {
  const errMsg = resp.message || resp.error?.message || JSON.stringify(resp).slice(0,200);
  const msg = `❌ 客戶建檔失敗\n\n姓名：${data.name}\n原因：${errMsg}\n\n可能原因：\n• Notion DB 沒分享給 integration（去 DB 右上 ⋯ → Connections 加入）\n• 欄位名被改過（必須是「客戶姓名/電話/公司/LINE / 通訊軟體/來源/狀態/標籤/備註/下次追蹤日」）`;
  return [{ json: { replyToken: data.replyToken, message: msg } }];
}

const s = data.summary;
const lines = ['✅ 客戶已建檔', '', `👤 ${data.name}`];
if (s.phone)    lines.push(`📞 ${s.phone}`);
if (s.company)  lines.push(`🏢 ${s.company}`);
if (s.lineId)   lines.push(`💬 ${s.lineId}`);
lines.push(`📥 來源：${s.source}　狀態：${s.status}`);
if (s.tags.length) lines.push(`🏷 ${s.tags.join('、')}`);
if (s.followup)    lines.push(`⏰ 追蹤：${s.followup}`);
if (resp.url)      lines.push('', resp.url);
return [{ json: { replyToken: data.replyToken, message: lines.join('\n') } }];

const data = $input.first().json;
return [{ json: { replyToken: data.replyToken, message: `❌ 客戶建檔失敗

原因：${data.reason}

格式範例：
• 客戶 王大明 0912345678 找三民區3房預算1500萬 介紹
• 客戶 陳小姐 LINE: abc123 想出租左營透天 急
（也可以直接傳一張名片照片）` } }];
